      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .board {
              position: relative;
              width: 100%;
              height: 100%;
              overflow: hidden;
              background: #111;
            }
            .cell {
              position: absolute;
              box-sizing: border-box;
              border: 1px solid rgba(255,255,255,0.04);
            }
            .snake-segment, .food {
              position: absolute;
              will-change: transform;
            }
            .snake-segment {
              background: linear-gradient(180deg, #7cff7c, #33cc33);
              border-radius: 25%;
              transition: transform 120ms linear;
            }
            .head {
              background: linear-gradient(180deg, #b6ffb6, #5bff5b);
              box-shadow: 0 0 10px rgba(124,255,124,0.35);
            }
            .food {
              background: #ff4d4d;
              border-radius: 50%;
              box-shadow: 0 0 10px rgba(255,77,77,0.5);
              transition: transform 120ms linear;
            }
          </style>
          <div class="board"></div>
        `

        const board = parent.querySelector(".board")
        const cols = 20
        const rows = 20
        const cellSize = 20
        const boardW = cols * cellSize
        const boardH = rows * cellSize
        board.style.width = `${boardW}px`
        board.style.height = `${boardH}px`

        let snake = [
          { x: 10, y: 10 },
          { x: 9, y: 10 },
          { x: 8, y: 10 }
        ]
        let prevSnake = snake.map(p => ({ ...p }))
        let dir = { x: 1, y: 0 }
        let nextDir = { x: 1, y: 0 }
        let food = spawnFood()
        let score = 0
        let alive = true
        let tick = 0

        const cells = []
        for (let y = 0; y < rows; y++) {
          for (let x = 0; x < cols; x++) {
            const c = document.createElement("div")
            c.className = "cell"
            c.style.left = `${x * cellSize}px`
            c.style.top = `${y * cellSize}px`
            c.style.width = `${cellSize}px`
            c.style.height = `${cellSize}px`
            board.appendChild(c)
            cells.push(c)
          }
        }

        const foodEl = document.createElement("div")
        foodEl.className = "food"
        foodEl.style.width = `${cellSize * 0.7}px`
        foodEl.style.height = `${cellSize * 0.7}px`
        board.appendChild(foodEl)

        const snakeEls = snake.map((_, i) => {
          const el = document.createElement("div")
          el.className = "snake-segment" + (i === 0 ? " head" : "")
          el.style.width = `${cellSize * 0.9}px`
          el.style.height = `${cellSize * 0.9}px`
          board.appendChild(el)
          return el
        })

        window.addEventListener("keydown", (e) => {
          const map = {
            ArrowUp: { x: 0, y: -1 },
            ArrowDown: { x: 0, y: 1 },
            ArrowLeft: { x: -1, y: 0 },
            ArrowRight: { x: 1, y: 0 }
          }
          const nd = map[e.key]
          if (!nd) return
          if (nd.x === -dir.x && nd.y === -dir.y) return
          nextDir = nd
        })

        function spawnFood() {
          while (true) {
            const p = {
              x: Math.floor(Math.random() * cols),
              y: Math.floor(Math.random() * rows)
            }
            if (!snake || !snake.some(s => s.x === p.x && s.y === p.y)) return p
          }
        }

        function step() {
          if (!alive) return

          prevSnake = snake.map(p => ({ ...p }))
          dir = nextDir
          const head = snake[0]
          const newHead = { x: head.x + dir.x, y: head.y + dir.y }

          if (
            newHead.x < 0 || newHead.x >= cols ||
            newHead.y < 0 || newHead.y >= rows ||
            snake.some((s, i) => i !== snake.length - 1 && s.x === newHead.x && s.y === newHead.y)
          ) {
            alive = false
            return
          }

          snake = [newHead, ...snake.slice(0, -1)]

          if (newHead.x === food.x && newHead.y === food.y) {
            snake.push({ ...snake[snake.length - 1] })
            snakeEls.push(createSegment())
            food = spawnFood()
            score++
          }

          render(true)
        }

        function createSegment() {
          const el = document.createElement("div")
          el.className = "snake-segment"
          el.style.width = `${cellSize * 0.9}px`
          el.style.height = `${cellSize * 0.9}px`
          board.appendChild(el)
          return el
        }

        function render(animated) {
          const alpha = animated ? 1 : 1
          snake.forEach((seg, i) => {
            const el = snakeEls[i] || createSegment()
            snakeEls[i] = el
            el.className = "snake-segment" + (i === 0 ? " head" : "")
            const from = prevSnake[i] || snake[i]
            const to = seg
            const x = from.x + (to.x - from.x) * alpha
            const y = from.y + (to.y - from.y) * alpha
            el.style.transform = `translate(${x * cellSize + cellSize * 0.05}px, ${y * cellSize + cellSize * 0.05}px)`
          })
          foodEl.style.transform = `translate(${food.x * cellSize + cellSize * 0.15}px, ${food.y * cellSize + cellSize * 0.15}px)`
        }

        function loop() {
          if (!alive) {
            render(true)
            return
          }
          tick++
          if (tick % 6 === 0) step()
          render(false)
          requestAnimationFrame(loop)
        }

        render(false)
        requestAnimationFrame(loop)
      }
    }
  ]
})

